Map<String, Integer> map = new HashMap<>();
map.put("alice", 30);
map.put("bob", 25);

// O(1) average get
int age = map.get("alice");  // 30

// Merge pattern (avoid get + put)
map.merge("alice", 1, Integer::sum);  // increments alice's value by 1

// computeIfAbsent — lazy initialization
Map<String, List<String>> groups = new HashMap<>();
groups.computeIfAbsent("team-a", k -> new ArrayList<>()).add("alice");

// Broken: equals without hashCode
public class Point {
    int x, y;
    @Override public boolean equals(Object o) {
        if (!(o instanceof Point p)) return false;
        return x == p.x && y == p.y;
    }
    // Missing hashCode! HashMap will never find inserted Points
}

// Correct
public class Point {
    int x, y;
    @Override public boolean equals(Object o) {
        if (!(o instanceof Point p)) return false;
        return x == p.x && y == p.y;
    }
    @Override public int hashCode() {
        return Objects.hash(x, y);  // consistent with equals
    }
}

// Bad: O(n²) due to repeated String allocation
String result = "";
for (int i = 0; i < 1000; i++) {
    result += i;  // creates a new String each iteration!
}

// Good: O(n) with StringBuilder
StringBuilder sb = new StringBuilder();
for (int i = 0; i < 1000; i++) {
    sb.append(i);
}
String result = sb.toString();

// Note: the compiler optimises simple + in a single expression
String s = "Hello" + " " + "World"; // compiled to StringBuilder internally

// Array — fixed size, primitives allowed
int[] scores = new int[5];  // no boxing overhead
scores[0] = 42;
// scores[5] = 1;  // ArrayIndexOutOfBoundsException at runtime

// ArrayList — dynamic, objects only
List<Integer> list = new ArrayList<>();  // Integer, not int (boxed)
list.add(42);  // auto-boxes int → Integer
list.add(99);
list.remove(Integer.valueOf(42));  // removes by value, not index

// Convert between them
int[] arr = {1, 2, 3};
List<Integer> fromArr = new ArrayList<>(Arrays.asList(1, 2, 3));
int[] backToArr = list.stream().mapToInt(Integer::intValue).toArray();

// LinkedList as a Deque (double-ended queue) — its best use case
Deque<String> deque = new LinkedList<>();
deque.addFirst("a");   // O(1)
deque.addLast("b");    // O(1)
deque.addFirst("z");   // O(1)
System.out.println(deque);  // [z, a, b]
deque.pollFirst();          // removes and returns "z"

// For queue/stack use cases, prefer ArrayDeque
Deque<String> fast = new ArrayDeque<>(); // better cache performance than LinkedList
fast.push("x");
fast.pop();

// LinkedList get(index) is O(n) — avoid in loops
LinkedList<Integer> list = new LinkedList<>(List.of(1,2,3,4,5));
int mid = list.get(2);  // traverses from head — slow for large lists
